// src/core/weather-icons.js
// Погодні іконки (заміна emoji ☀️🌧️❄️ тощо) — Meteocons (github.com/basmilius/meteocons,
// MIT), варіант `line` (кольоровий, statyc SVG без анімації). Tabler тут навмисно НЕ
// використано — немає окремих іконок "мінлива хмарність"/"мряка" (перевірено 404),
// довелось би плутати різні стани WMO-кодів однією іконкою. Base64 (не сирий inline SVG) —
// ці іконки мають внутрішні <mask>/<clipPath> з id, при 2+ однакових іконках на сторінці
// (напр. 2 сонячні дні в прогнозі на 7 днів) id збігались би і друга іконка ламалась.
//
// Використання: <img class="wx-ic" src="..." alt="..."> — розмір через CSS (1em, як .cat-ico).

const WX_CLEAR_DAY = 'data:image/svg+xml;base64,';
const WX_PARTLY_CLOUDY = 'data:image/svg+xml;base64,';
const WX_OVERCAST = 'data:image/svg+xml;base64,';
const WX_FOG = 'data:image/svg+xml;base64,';
const WX_DRIZZLE = 'data:image/svg+xml;base64,';
const WX_RAIN = 'data:image/svg+xml;base64,';
const WX_SNOW = 'data:image/svg+xml;base64,';
const WX_SNOW_SHOWERS = 'data:image/svg+xml;base64,';
const WX_THUNDERSTORMS = 'data:image/svg+xml;base64,';
const WX_CLOUDY = 'data:image/svg+xml;base64,';

// WMO weather code (Open-Meteo) → { icon: <img>, text: опис укр. } — межі кодів ідентичні
// попередній emoji-версії (community-blocks.js), не перевигадую класифікацію.
export function weatherCodeInfo(code) {
  const img = (src, alt) => `<img class="wx-ic" src="${src}" alt="${alt}">`;
  if (code === 0) return { icon: img(WX_CLEAR_DAY, 'Ясно'), text: 'Ясно' };
  if (code <= 2)  return { icon: img(WX_PARTLY_CLOUDY, 'Мінлива хмарність'), text: 'Мінлива хмарність' };
  if (code === 3) return { icon: img(WX_OVERCAST, 'Хмарно'), text: 'Хмарно' };
  if (code <= 48) return { icon: img(WX_FOG, 'Туман'), text: 'Туман' };
  if (code <= 55) return { icon: img(WX_DRIZZLE, 'Мряка'), text: 'Мряка' };
  if (code <= 65) return { icon: img(WX_RAIN, 'Дощ'), text: 'Дощ' };
  if (code <= 77) return { icon: img(WX_SNOW, 'Сніг'), text: 'Сніг' };
  if (code <= 82) return { icon: img(WX_RAIN, 'Зливи'), text: 'Зливи' };
  if (code <= 86) return { icon: img(WX_SNOW_SHOWERS, 'Снігові зливи'), text: 'Снігові зливи' };
  if (code >= 95) return { icon: img(WX_THUNDERSTORMS, 'Гроза'), text: 'Гроза' };
  return { icon: img(WX_CLOUDY, '—'), text: '—' };
}
